        // State: tsqf
        inner.states.insert("tsqf".to_string(), vec![
            LexerRule { pattern: TokenPattern::new(r"'''", Token::STRING_SINGLE).unwrap(), action: LexerAction::PopN(1) },
            LexerRule { pattern: TokenPattern::new(r"\n", Token::STRING_SINGLE).unwrap(), action: LexerAction::token(Token::STRING_SINGLE) },
        ]);

        // State: tdqs
        inner.states.insert("tdqs".to_string(), vec![
            LexerRule { pattern: TokenPattern::new(r##"""""##, Token::STRING_DOUBLE).unwrap(), action: LexerAction::PopN(1) },
            LexerRule { pattern: TokenPattern::new(r"\n", Token::STRING_DOUBLE).unwrap(), action: LexerAction::token(Token::STRING_DOUBLE) },
        ]);

        // State: tsqs
        inner.states.insert("tsqs".to_string(), vec![
            LexerRule { pattern: TokenPattern::new(r"'''", Token::STRING_SINGLE).unwrap(), action: LexerAction::PopN(1) },
            LexerRule { pattern: TokenPattern::new(r"\n", Token::STRING_SINGLE).unwrap(), action: LexerAction::token(Token::STRING_SINGLE) },
        ]);

        MojoLexer { inner }
